import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.DCVnL8g5.js";const g=JSON.parse('{"title":"Entidades value objects y agregados","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/03-entidades-value-objects-y-agregados.md","filePath":"full-stack/arquitectura/ddd/03-entidades-value-objects-y-agregados.md","lastUpdated":1782521464000}'),t={name:"full-stack/arquitectura/ddd/03-entidades-value-objects-y-agregados.md"};function o(l,a,d,r,p,c){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="entidades-value-objects-y-agregados" tabindex="-1">Entidades value objects y agregados <a class="header-anchor" href="#entidades-value-objects-y-agregados" aria-label="Permalink to &quot;Entidades value objects y agregados&quot;">​</a></h1><p>DDD tactico ofrece patrones para modelar reglas de negocio sin convertir todo en tablas, DTOs o clases anemicas.</p><h2 id="entidades" tabindex="-1">Entidades <a class="header-anchor" href="#entidades" aria-label="Permalink to &quot;Entidades&quot;">​</a></h2><p>Una entidad tiene identidad y ciclo de vida.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User</span></span>
<span class="line"><span>Order</span></span>
<span class="line"><span>Course</span></span>
<span class="line"><span>Invoice</span></span></code></pre></div><p>Dos pedidos con los mismos datos no son el mismo pedido si tienen IDs distintos.</p><h2 id="value-objects" tabindex="-1">Value objects <a class="header-anchor" href="#value-objects" aria-label="Permalink to &quot;Value objects&quot;">​</a></h2><p>Un value object se define por sus valores, no por identidad.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Money(amount, currency)</span></span>
<span class="line"><span>EmailAddress(value)</span></span>
<span class="line"><span>DateRange(start, end)</span></span>
<span class="line"><span>Address(street, city, country)</span></span></code></pre></div><p>Son utiles para encapsular validaciones:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EmailAddress</span></span>
<span class="line"><span>  - debe tener formato valido</span></span>
<span class="line"><span>  - se normaliza en minusculas</span></span></code></pre></div><h2 id="agregados" tabindex="-1">Agregados <a class="header-anchor" href="#agregados" aria-label="Permalink to &quot;Agregados&quot;">​</a></h2><p>Un agregado es un grupo de objetos que se modifica como una unidad consistente.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Order</span></span>
<span class="line"><span>  OrderLine[]</span></span>
<span class="line"><span>  ShippingAddress</span></span>
<span class="line"><span>  PaymentStatus</span></span></code></pre></div><p>El agregado tiene una raiz. Desde fuera se modifica a traves de esa raiz.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order.addLine(product, quantity)</span></span>
<span class="line"><span>order.confirm()</span></span>
<span class="line"><span>order.cancel(reason)</span></span></code></pre></div><h2 id="invariantes" tabindex="-1">Invariantes <a class="header-anchor" href="#invariantes" aria-label="Permalink to &quot;Invariantes&quot;">​</a></h2><p>Una invariante es una regla que siempre debe cumplirse.</p><p>Ejemplos:</p><ul><li>Un pedido confirmado debe tener al menos una linea.</li><li>Una factura pagada no puede modificarse.</li><li>Un curso publicado debe tener titulo y al menos una leccion.</li><li>Una reserva no puede superar el aforo disponible.</li></ul><h2 id="tamano-del-agregado" tabindex="-1">Tamano del agregado <a class="header-anchor" href="#tamano-del-agregado" aria-label="Permalink to &quot;Tamano del agregado&quot;">​</a></h2><p>Agregados demasiado grandes generan bloqueos, transacciones pesadas y modelos dificiles de entender.</p><p>Regla practica:</p><ul><li>Agrega lo que necesite consistencia inmediata.</li><li>Comunica lo demas con eventos.</li><li>Evita cargar colecciones enormes dentro de la raiz.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las entidades protegen reglas, no solo almacenan datos.</li><li>Los value objects eliminan strings y numeros ambiguos.</li><li>Los agregados tienen limites claros.</li><li>Las invariantes viven cerca del modelo que protegen.</li><li>No se modifican objetos internos saltandose la raiz del agregado.</li></ul>`,26)])])}const h=e(t,[["render",o]]);export{g as __pageData,h as default};
